import React, { useState } from 'react';
import axios from 'axios';

function NoteForm({ fetchNotes }) {
  const [form, setForm] = useState({ title: '', content: '' });

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.title || !form.content) return;
    try {
      await axios.post('http://localhost:5001/api/notes', form);
      fetchNotes();
      setForm({ title: '', content: '' });
    } catch (err) { console.error(err); }
  };

  const inputLabel = { fontSize: '12px', fontWeight: '700', color: '#94a3b8', textTransform: 'uppercase', marginBottom: '8px', display: 'block' };

  const inputBase = {
    width: '100%',
    padding: '14px',
    borderRadius: '12px',
    border: '1px solid #e2e8f0',
    backgroundColor: '#f1f5f9',
    fontSize: '15px',
    marginBottom: '20px',
    outline: 'none',
    boxSizing: 'border-box',
    transition: 'all 0.2s'
  };

  return (
    <form onSubmit={handleSubmit} style={{ width: '100%' }}>
      <label style={inputLabel}>Topic Title</label>
      <input
        style={inputBase}
        placeholder="e.g. Terraform State Lock"
        value={form.title}
        onChange={e => setForm({ ...form, title: e.target.value })}
        onFocus={(e) => { e.target.style.backgroundColor = '#fff'; e.target.style.borderColor = '#6366f1'; }}
        onBlur={(e) => { e.target.style.backgroundColor = '#f1f5f9'; e.target.style.borderColor = '#e2e8f0'; }}
      />

      <label style={inputLabel}>Detailed content</label>
      <textarea
        style={{ ...inputBase, height: '180px', resize: 'none' }}
        placeholder="Document the process..."
        value={form.content}
        onChange={e => setForm({ ...form, content: e.target.value })}
        onFocus={(e) => { e.target.style.backgroundColor = '#fff'; e.target.style.borderColor = '#6366f1'; }}
        onBlur={(e) => { e.target.style.backgroundColor = '#f1f5f9'; e.target.style.borderColor = '#e2e8f0'; }}
      />

      <button 
        type="submit" 
        style={{
          width: '100%',
          padding: '16px',
          backgroundColor: '#6366f1',
          color: 'white',
          border: 'none',
          borderRadius: '12px',
          fontWeight: '700',
          cursor: 'pointer',
          boxShadow: '0 4px 14px 0 rgba(99, 102, 241, 0.39)'
        }}
      >
        Save Note
      </button>
    </form>
  );
}

export default NoteForm;
